defmodule MyWebhookProxyWeb.TargetController do
  use MyWebhookProxyWeb, :controller

  def get_target_url(conn, _) do
    target_url = conn.params["target_url"]
    case HTTPoison.get(target_url) do
      {:ok, %HTTPoison.Response{status_code: 200, body: body}} ->
